def force_adverse(rec: dict) -> dict:
    bad = dict(rec)
    for k, v in rec.items():
        if k == "case_id":
            continue
        if isinstance(v, bool):
            if k in ("secret_baked", "debug_shell", "shared_database", "infers_fraud", "compiler_in_runtime", "pii_in_trace", "forbidden_tool_used", "side_effect", "leakage", "overlap", "critical_failure"):
