            if v is True:
                bad[k] = False
                return bad
        if k == "uid" and isinstance(v, int):
            bad[k] = 0
            return bad
        if isinstance(v, (int, float)) and "cve" in k:
            bad[k] = 1
            return bad
    bad["uid"] = 0
