def decide(record: dict) -> str:
    required = {"case_id", "critical_failure", "pipeline_blocked", "logs_redacted", "owner", "evidence_retained"}
    missing = sorted(required - record.keys())
    if missing:
        # absence is not breach
        return "ASSIGN_INCIDENT_OWNER"
    ok = not (record["critical_failure"] and not record["pipeline_blocked"])
    return "CONTINUE" if ok else "STOP_SILENT_FAILURE"

